export function aStarGridShortestPath(
	grid: number[][],
	start: readonly [number, number],
	end: readonly [number, number]
): number | null {
	const rows = grid.length;
	if (rows === 0) return null;
	const cols = grid[0]?.length ?? 0;
	if (cols === 0) return null;

	const [sr, sc] = start;
	const [er, ec] = end;

	const inBounds = (r: number, c: number) => r >= 0 && r < rows && c >= 0 && c < cols;

	if (!inBounds(sr, sc) || !inBounds(er, ec)) return null;
	if (grid[sr][sc] !== 0 || grid[er][ec] !== 0) return null;
	if (sr === er && sc === ec) return 0;

	const h = (r: number, c: number) => Math.abs(r - er) + Math.abs(c - ec);

	const gScore: number[][] = Array.from({ length: rows }, () => Array(cols).fill(Infinity));
	const inOpen: boolean[][] = Array.from({ length: rows }, () => Array(cols).fill(false));
	gScore[sr][sc] = 0;

	type Node = { r: number; c: number; g: number; f: number };
	const open: Node[] = [{ r: sr, c: sc, g: 0, f: h(sr, sc) }];
	inOpen[sr][sc] = true;

	const dirs: readonly (readonly [number, number])[] = [
		[1, 0],
		[-1, 0],
		[0, 1],
		[0, -1]
	];

	while (open.length > 0) {
		let bestIdx = 0;
		for (let i = 1; i < open.length; i++) {
			if (open[i].f < open[bestIdx].f || (open[i].f === open[bestIdx].f && open[i].g > open[bestIdx].g)) {
				bestIdx = i;
			}
		}

		const current = open[bestIdx];
		open.splice(bestIdx, 1);
		inOpen[current.r][current.c] = false;

		if (current.g !== gScore[current.r][current.c]) continue;

		if (current.r === er && current.c === ec) {
			return current.g;
		}

		for (const [dr, dc] of dirs) {
			const nr = current.r + dr;
			const nc = current.c + dc;

			if (!inBounds(nr, nc) || grid[nr][nc] !== 0) continue;

			const tentativeG = current.g + 1;
			if (tentativeG < gScore[nr][nc]) {
				gScore[nr][nc] = tentativeG;
				const node: Node = { r: nr, c: nc, g: tentativeG, f: tentativeG + h(nr, nc) };
				open.push(node);
				inOpen[nr][nc] = true;
			}
		}
	}

	return null;
}

export function binarySearchBoundary(values: number[], target: number): number {
	let left = 0;
	let right = values.length - 1;
	let boundary = -1;

	while (left <= right) {
		const mid = left + Math.floor((right - left) / 2);

		if (values[mid] === target) {
			boundary = mid;
			right = mid - 1;
		} else if (values[mid] < target) {
			left = mid + 1;
		} else {
			right = mid - 1;
		}
	}

	return boundary;
}

export function binarySearchFirstLastPosition(values: number[], target: number): [number, number] {
	const first = findBoundary(values, target, true);
	if (first === -1) return [-1, -1];
	const last = findBoundary(values, target, false);
	return [first, last];
}

function findBoundary(values: number[], target: number, findFirst: boolean): number {
	let left = 0;
	let right = values.length - 1;
	let result = -1;

	while (left <= right) {
		const mid = left + Math.floor((right - left) / 2);

		if (values[mid] === target) {
			result = mid;
			if (findFirst) {
				right = mid - 1;
			} else {
				left = mid + 1;
			}
		} else if (values[mid] < target) {
			left = mid + 1;
		} else {
			right = mid - 1;
		}
	}

	return result;
}

export function evaluateBooleanExpression(expression: string): boolean {
	const parser = new Parser(expression);
	const result = parser.parseExpression();
	parser.skipWhitespace();
	if (!parser.isEnd()) {
		throw new Error(`Unexpected token at position ${parser.pos}`);
	}
	return result;
}

class Parser {
	public pos = 0;
	private readonly input: string;

	constructor(input: string) {
		this.input = input;
	}

	isEnd(): boolean {
		return this.pos >= this.input.length;
	}

	skipWhitespace(): void {
		while (!this.isEnd() && /\s/.test(this.input[this.pos])) {
			this.pos++;
		}
	}

	parseExpression(): boolean {
		return this.parseOr();
	}

	private parseOr(): boolean {
		let left = this.parseAnd();
		while (true) {
			this.skipWhitespace();
			if (this.match("||")) {
				const right = this.parseAnd();
				left = left || right;
			} else {
				break;
			}
		}
		return left;
	}

	private parseAnd(): boolean {
		let left = this.parseUnary();
		while (true) {
			this.skipWhitespace();
			if (this.match("&&")) {
				const right = this.parseUnary();
				left = left && right;
			} else {
				break;
			}
		}
		return left;
	}

	private parseUnary(): boolean {
		this.skipWhitespace();
		if (this.match("!")) {
			return !this.parseUnary();
		}
		return this.parsePrimary();
	}

	private parsePrimary(): boolean {
		this.skipWhitespace();

		if (this.match("(")) {
			const value = this.parseExpression();
			this.skipWhitespace();
			if (!this.match(")")) {
				throw new Error(`Expected ')' at position ${this.pos}`);
			}
			return value;
		}

		if (this.matchKeyword("true")) return true;
		if (this.matchKeyword("false")) return false;

		throw new Error(`Unexpected token at position ${this.pos}`);
	}

	private match(token: string): boolean {
		this.skipWhitespace();
		if (this.input.startsWith(token, this.pos)) {
			this.pos += token.length;
			return true;
		}
		return false;
	}

	private matchKeyword(word: string): boolean {
		this.skipWhitespace();
		if (!this.input.startsWith(word, this.pos)) return false;

		const next = this.input[this.pos + word.length];
		if (next && /[A-Za-z0-9_]/.test(next)) return false;

		this.pos += word.length;
		return true;
	}
}

import * as fs from 'fs';
import * as path from 'path';

function isTsFile(filePath: string): boolean {
	return filePath.endsWith('.ts') && !filePath.endsWith('.d.ts');
}

function listTsFilesRecursive(rootDir: string): string[] {
	const result: string[] = [];

	function walk(current: string): void {
		const entries = fs.readdirSync(current, { withFileTypes: true });
		for (const entry of entries) {
			const fullPath = path.join(current, entry.name);
			if (entry.isDirectory()) {
				walk(fullPath);
			} else if (entry.isFile() && isTsFile(fullPath)) {
				result.push(fullPath);
			}
		}
	}

	walk(rootDir);
	return result;
}

function normalizePath(p: string): string {
	return path.normalize(p);
}

function resolveLocalImport(fromFile: string, specifier: string): string | null {
	if (!(specifier.startsWith('./') || specifier.startsWith('../'))) {
		return null;
	}

	const baseDir = path.dirname(fromFile);
	const candidateBase = normalizePath(path.resolve(baseDir, specifier));

	const candidates = [
		candidateBase,
		`${candidateBase}.ts`,
		path.join(candidateBase, 'index.ts'),
	];

	for (const candidate of candidates) {
		if (fs.existsSync(candidate) && fs.statSync(candidate).isFile() && isTsFile(candidate)) {
			return normalizePath(candidate);
		}
	}

	return null;
}

function parseLocalImports(filePath: string): string[] {
	const content = fs.readFileSync(filePath, 'utf8');
	const imports: string[] = [];

	const patterns = [
		/import\s+[^'"]*?from\s+['"]([^'"]+)['"]/g,
		/import\s*['"]([^'"]+)['"]/g,
		/export\s+[^'"]*?from\s+['"]([^'"]+)['"]/g,
		/require\s*\(\s*['"]([^'"]+)['"]\s*\)/g,
	];

	for (const pattern of patterns) {
		let match: RegExpExecArray | null;
		while ((match = pattern.exec(content)) !== null) {
			imports.push(match[1]);
		}
	}

	return imports;
}

function canonicalCycle(cycle: string[]): string {
	const n = cycle.length;
	if (n === 0) return '';
	let best: string[] | null = null;

	for (let i = 0; i < n; i++) {
		const rotated = cycle.slice(i).concat(cycle.slice(0, i));
		if (best === null) {
			best = rotated;
			continue;
		}
		const a = rotated.join('\u0000');
		const b = best.join('\u0000');
		if (a < b) best = rotated;
	}

	return (best ?? cycle).join('->');
}

export function detectCycles(rootDir: string): string[][] {
	const absRoot = normalizePath(path.resolve(rootDir));
	if (!fs.existsSync(absRoot) || !fs.statSync(absRoot).isDirectory()) {
		return [];
	}

	const files = listTsFilesRecursive(absRoot).map(normalizePath);
	const fileSet = new Set(files);

	const graph = new Map<string, string[]>();
	for (const file of files) {
		const specs = parseLocalImports(file);
		const neighbors: string[] = [];
		for (const spec of specs) {
			const resolved = resolveLocalImport(file, spec);
			if (resolved && fileSet.has(resolved)) {
				neighbors.push(resolved);
			}
		}
		graph.set(file, Array.from(new Set(neighbors)));
	}

	const cycles: string[][] = [];
	const seen = new Set<string>();
	const visited = new Set<string>();
	const inStack = new Set<string>();
	const stack: string[] = [];
	const indexInStack = new Map<string, number>();

	function dfs(node: string): void {
		visited.add(node);
		inStack.add(node);
		indexInStack.set(node, stack.length);
		stack.push(node);

		const neighbors = graph.get(node) ?? [];
		for (const next of neighbors) {
			if (!visited.has(next)) {
				dfs(next);
			} else if (inStack.has(next)) {
				const startIdx = indexInStack.get(next);
				if (startIdx !== undefined) {
					const cycle = stack.slice(startIdx);
					const key = canonicalCycle(cycle);
					if (!seen.has(key)) {
						seen.add(key);
						cycles.push(cycle);
					}
				}
			}
		}

		stack.pop();
		inStack.delete(node);
		indexInStack.delete(node);
	}

	for (const file of files) {
		if (!visited.has(file)) {
			dfs(file);
		}
	}

	return cycles;
}

export function runCli(args: readonly string[]): number {
	const rootArg = args[0] ?? '.';
	const cycles = detectCycles(rootArg);

	for (const cycle of cycles) {
		const printable = cycle.concat(cycle[0]).join(' -> ');
		console.log(printable);
	}

	return cycles.length > 0 ? 1 : 0;
}

export function dijkstraShortestPath(
	nodeCount: number,
	edges: readonly (readonly [number, number, number])[],
	start: number,
	end: number
): number | null {
	if (
		nodeCount <= 0 ||
		start < 0 ||
		start >= nodeCount ||
		end < 0 ||
		end >= nodeCount
	) {
		return null;
	}

	if (start === end) return 0;

	const adjacency: Array<Array<[number, number]>> = Array.from(
		{ length: nodeCount },
		() => []
	);

	for (const [from, to, weight] of edges) {
		if (
			from >= 0 &&
			from < nodeCount &&
			to >= 0 &&
			to < nodeCount &&
			weight >= 0
		) {
			adjacency[from].push([to, weight]);
		}
	}

	const dist: number[] = Array(nodeCount).fill(Infinity);
	const visited: boolean[] = Array(nodeCount).fill(false);
	dist[start] = 0;

	for (let i = 0; i < nodeCount; i++) {
		let u = -1;
		let best = Infinity;

		for (let v = 0; v < nodeCount; v++) {
			if (!visited[v] && dist[v] < best) {
				best = dist[v];
				u = v;
			}
		}

		if (u === -1 || best === Infinity) break;
		if (u === end) break;

		visited[u] = true;

		for (const [to, weight] of adjacency[u]) {
			if (visited[to]) continue;
			const alt = dist[u] + weight;
			if (alt < dist[to]) {
				dist[to] = alt;
			}
		}
	}

	return dist[end] === Infinity ? null : dist[end];
}

export function fftBigintMultiplyDigitArrays(a: number[], b: number[]): number[] {
	if (a.length === 0 || b.length === 0) return [0];

	const trimLeadingZeros = (arr: number[]): number[] => {
		let i = 0;
		while (i < arr.length - 1 && arr[i] === 0) i++;
		return arr.slice(i);
	};

	a = trimLeadingZeros(a);
	b = trimLeadingZeros(b);

	if ((a.length === 1 && a[0] === 0) || (b.length === 1 && b[0] === 0)) {
		return [0];
	}

	const n = a.length;
	const m = b.length;
	const res = new Array<number>(n + m).fill(0);

	for (let i = n - 1; i >= 0; i--) {
		let carry = 0;
		for (let j = m - 1; j >= 0; j--) {
			const idx = i + j + 1;
			const prod = a[i] * b[j] + res[idx] + carry;
			res[idx] = prod % 10;
			carry = Math.floor(prod / 10);
		}
		res[i] += carry;
	}

	for (let k = res.length - 1; k > 0; k--) {
		if (res[k] >= 10) {
			const c = Math.floor(res[k] / 10);
			res[k] %= 10;
			res[k - 1] += c;
		}
	}

	return trimLeadingZeros(res);
}

export function fibonacci(n: number): number {
	if (n < 0 || !Number.isInteger(n)) {
		throw new Error('n must be a non-negative integer');
	}

	if (n === 0) return 0;
	if (n === 1) return 1;

	let prev = 0;
	let curr = 1;

	for (let i = 2; i <= n; i++) {
		const next = prev + curr;
		prev = curr;
		curr = next;
	}

	return curr;
}

export function groupAnagrams(words: string[]): string[][] {
	const groups = new Map<string, string[]>();

	for (const word of words) {
		const key = word.split('').sort().join('');
		const existing = groups.get(key);
		if (existing) {
			existing.push(word);
		} else {
			groups.set(key, [word]);
		}
	}

	return Array.from(groups.values());
}

export function integerBreakMaxProduct(n: number): number {
	if (n <= 3) return n - 1;

	let product = 1;
	while (n > 4) {
		product *= 3;
		n -= 3;
	}
	return product * n;
}

export function longestCommonSubsequence(a: string, b: string): number {
	const m = a.length;
	const n = b.length;

	const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));

	for (let i = 1; i <= m; i++) {
		for (let j = 1; j <= n; j++) {
			if (a[i - 1] === b[j - 1]) {
				dp[i][j] = dp[i - 1][j - 1] + 1;
			} else {
				dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
			}
		}
	}

	return dp[m][n];
}

export function longestSubstringNoRepeat(input: string): number {
	let maxLength = 0;
	let windowStart = 0;
	const lastSeen = new Map<string, number>();

	for (let i = 0; i < input.length; i++) {
		const char = input[i];
		const prevIndex = lastSeen.get(char);

		if (prevIndex !== undefined && prevIndex >= windowStart) {
			windowStart = prevIndex + 1;
		}

		lastSeen.set(char, i);
		const currentLength = i - windowStart + 1;
		if (currentLength > maxLength) {
			maxLength = currentLength;
		}
	}

	return maxLength;
}

export function lruCache(
	capacity: number,
	operations: readonly (readonly ['get' | 'put', number, number?])[]
): (number | null)[] {
	const outputs: (number | null)[] = [];

	if (capacity <= 0) {
		for (const [op] of operations) {
			outputs.push(op === 'get' ? -1 : null);
		}
		return outputs;
	}

	const cache = new Map<number, number>();

	for (const opTuple of operations) {
		const [op, key, value] = opTuple;

		if (op === 'get') {
			if (!cache.has(key)) {
				outputs.push(-1);
			} else {
				const v = cache.get(key)!;
				cache.delete(key);
				cache.set(key, v);
				outputs.push(v);
			}
		} else {
			if (cache.has(key)) {
				cache.delete(key);
			} else if (cache.size >= capacity) {
				const lruKey = cache.keys().next().value as number;
				cache.delete(lruKey);
			}
			cache.set(key, value as number);
			outputs.push(null);
		}
	}

	return outputs;
}

export function mergeIntervals(intervals: [number, number][]): [number, number][] {
	if (intervals.length <= 1) return intervals.slice();

	const sorted = intervals.slice().sort((a, b) => a[0] - b[0]);
	const merged: [number, number][] = [];

	let [currentStart, currentEnd] = sorted[0];

	for (let i = 1; i < sorted.length; i++) {
		const [start, end] = sorted[i];

		if (start <= currentEnd) {
			currentEnd = Math.max(currentEnd, end);
		} else {
			merged.push([currentStart, currentEnd]);
			currentStart = start;
			currentEnd = end;
		}
	}

	merged.push([currentStart, currentEnd]);
	return merged;
}

type ListNode = { value: number; next: ListNode | null };

export function mergeSortLinkedList(head: { value: number; next: any } | null): { value: number; next: any } | null {
	const listHead = head as ListNode | null;
	if (listHead === null || listHead.next === null) return listHead;

	const middle = splitMiddle(listHead);
	const leftSorted = mergeSortLinkedList(listHead) as ListNode | null;
	const rightSorted = mergeSortLinkedList(middle) as ListNode | null;

	return mergeLists(leftSorted, rightSorted);
}

function splitMiddle(head: ListNode): ListNode | null {
	let slow: ListNode = head;
	let fast: ListNode | null = head.next;

	while (fast !== null && fast.next !== null) {
		slow = slow.next as ListNode;
		fast = fast.next.next;
	}

	const middle = slow.next;
	slow.next = null;
	return middle;
}

function mergeLists(a: ListNode | null, b: ListNode | null): ListNode | null {
	const dummy: ListNode = { value: 0, next: null };
	let tail: ListNode = dummy;

	while (a !== null && b !== null) {
		if (a.value <= b.value) {
			tail.next = a;
			a = a.next;
		} else {
			tail.next = b;
			b = b.next;
		}
		tail = tail.next;
	}

	tail.next = a !== null ? a : b;
	return dummy.next;
}

export function minStack(
	operations: readonly (readonly ['push' | 'pop' | 'top' | 'getMin', number?])[],
): (number | null)[] {
	const stack: number[] = [];
	const minStackArr: number[] = [];
	const result: (number | null)[] = [];

	for (const [op, value] of operations) {
		if (op === 'push') {
			if (typeof value === 'number') {
				stack.push(value);
				if (minStackArr.length === 0) {
					minStackArr.push(value);
				} else {
					const currentMin = minStackArr[minStackArr.length - 1];
					minStackArr.push(value < currentMin ? value : currentMin);
				}
			}
			result.push(null);
		} else if (op === 'pop') {
			if (stack.length > 0) {
				stack.pop();
				minStackArr.pop();
			}
			result.push(null);
		} else if (op === 'top') {
			result.push(stack.length > 0 ? stack[stack.length - 1] : null);
		} else if (op === 'getMin') {
			result.push(minStackArr.length > 0 ? minStackArr[minStackArr.length - 1] : null);
		}
	}

	return result;
}

export function murmurhash3(str: string, seed: number): number {
	let h1 = seed | 0;
	const c1 = 0xcc9e2d51;
	const c2 = 0x1b873593;

	const len = str.length;
	let i = 0;

	while (i + 1 < len) {
		let k1 = (str.charCodeAt(i) & 0xffff) | ((str.charCodeAt(i + 1) & 0xffff) << 16);
		i += 2;

		k1 = Math.imul(k1, c1);
		k1 = (k1 << 15) | (k1 >>> 17);
		k1 = Math.imul(k1, c2);

		h1 ^= k1;
		h1 = (h1 << 13) | (h1 >>> 19);
		h1 = (Math.imul(h1, 5) + 0xe6546b64) | 0;
	}

	if (i < len) {
		let k1 = str.charCodeAt(i) & 0xffff;
		k1 = Math.imul(k1, c1);
		k1 = (k1 << 15) | (k1 >>> 17);
		k1 = Math.imul(k1, c2);
		h1 ^= k1;
	}

	h1 ^= len * 2;
	h1 ^= h1 >>> 16;
	h1 = Math.imul(h1, 0x85ebca6b);
	h1 ^= h1 >>> 13;
	h1 = Math.imul(h1, 0xc2b2ae35);
	h1 ^= h1 >>> 16;

	return h1 >>> 0;
}

export function numberOfIslands(grid: string[][]): number {
	if (!grid.length || !grid[0].length) return 0;

	const rows = grid.length;
	const cols = grid[0].length;
	let islands = 0;

	const dfs = (r: number, c: number): void => {
		if (r < 0 || c < 0 || r >= rows || c >= cols || grid[r][c] !== '1') return;
		grid[r][c] = '0';
		dfs(r + 1, c);
		dfs(r - 1, c);
		dfs(r, c + 1);
		dfs(r, c - 1);
	};

	for (let r = 0; r < rows; r++) {
		for (let c = 0; c < cols; c++) {
			if (grid[r][c] === '1') {
				islands++;
				dfs(r, c);
			}
		}
	}

	return islands;
}

export function productOfArrayExceptSelf(values: number[]): number[] {
	const n = values.length;
	const result = new Array<number>(n).fill(1);

	let prefix = 1;
	for (let i = 0; i < n; i++) {
		result[i] = prefix;
		prefix *= values[i];
	}

	let suffix = 1;
	for (let i = n - 1; i >= 0; i--) {
		result[i] *= suffix;
		suffix *= values[i];
	}

	return result;
}

export function quickselectKthSmallest(values: number[], k: number): number {
	if (!Number.isInteger(k) || k < 1 || k > values.length) {
		throw new Error('k is out of range');
	}

	const arr = values.slice();
	const target = k - 1;

	let left = 0;
	let right = arr.length - 1;

	while (left <= right) {
		const pivotIndex = partition(arr, left, right);
		if (pivotIndex === target) return arr[pivotIndex];
		if (pivotIndex < target) {
			left = pivotIndex + 1;
		} else {
			right = pivotIndex - 1;
		}
	}

	throw new Error('Unable to find kth smallest element');
}

function partition(arr: number[], left: number, right: number): number {
	const pivot = arr[right];
	let storeIndex = left;

	for (let i = left; i < right; i++) {
		if (arr[i] < pivot) {
			[arr[i], arr[storeIndex]] = [arr[storeIndex], arr[i]];
			storeIndex++;
		}
	}

	[arr[storeIndex], arr[right]] = [arr[right], arr[storeIndex]];
	return storeIndex;
}

export function quicksort(arr: number[]): number[] {
	if (arr.length <= 1) {
		return [...arr];
	}

	const [pivot, ...rest] = arr;
	const left: number[] = [];
	const right: number[] = [];

	for (const value of rest) {
		if (value < pivot) {
			left.push(value);
		} else {
			right.push(value);
		}
	}

	return [...quicksort(left), pivot, ...quicksort(right)];
}

export function topKFrequent(values: number[], k: number): number[] {
	if (k <= 0 || values.length === 0) return [];

	const freq = new Map<number, number>();
	for (const v of values) {
		freq.set(v, (freq.get(v) ?? 0) + 1);
	}

	return [...freq.entries()]
		.sort((a, b) => b[1] - a[1])
		.slice(0, Math.min(k, freq.size))
		.map(([num]) => num);
}

export function toyRsaBigint(
	p: bigint,
	q: bigint,
	e: bigint,
	message: bigint
): {
	publicKey: { n: bigint; e: bigint };
	privateKey: { n: bigint; d: bigint };
	cipher: bigint;
	decrypted: bigint;
} {
	const n = p * q;
	const phi = (p - 1n) * (q - 1n);

	function gcd(a: bigint, b: bigint): bigint {
		a = a < 0n ? -a : a;
		b = b < 0n ? -b : b;
		while (b !== 0n) {
			const t = b;
			b = a % b;
			a = t;
		}
		return a;
	}

	function egcd(a: bigint, b: bigint): { g: bigint; x: bigint; y: bigint } {
		let oldR = a;
		let r = b;
		let oldS = 1n;
		let s = 0n;
		let oldT = 0n;
		let t = 1n;

		while (r !== 0n) {
			const q = oldR / r;
			[oldR, r] = [r, oldR - q * r];
			[oldS, s] = [s, oldS - q * s];
			[oldT, t] = [t, oldT - q * t];
		}

		return { g: oldR, x: oldS, y: oldT };
	}

	function modInverse(a: bigint, m: bigint): bigint {
		const { g, x } = egcd(a, m);
		if (g !== 1n && g !== -1n) {
			throw new Error('e is not invertible modulo phi(n)');
		}
		const inv = x % m;
		return inv >= 0n ? inv : inv + m;
	}

	function modPow(base: bigint, exp: bigint, mod: bigint): bigint {
		if (mod === 1n) return 0n;
		let result = 1n;
		let b = ((base % mod) + mod) % mod;
		let eLocal = exp;
		while (eLocal > 0n) {
			if ((eLocal & 1n) === 1n) result = (result * b) % mod;
			b = (b * b) % mod;
			eLocal >>= 1n;
		}
		return result;
	}

	if (p <= 1n || q <= 1n) {
		throw new Error('p and q must be > 1');
	}
	if (e <= 1n || e >= phi) {
		throw new Error('e must satisfy 1 < e < phi(n)');
	}
	if (message < 0n || message >= n) {
		throw new Error('message must satisfy 0 <= message < n');
	}
	if (gcd(e, phi) !== 1n) {
		throw new Error('e must be coprime with phi(n)');
	}

	const d = modInverse(e, phi);
	const cipher = modPow(message, e, n);
	const decrypted = modPow(cipher, d, n);

	return {
		publicKey: { n, e },
		privateKey: { n, d },
		cipher,
		decrypted
	};
}

export function twoSum(nums: number[], target: number): [number, number] | null {
	const indexByValue = new Map<number, number>();

	for (let i = 0; i < nums.length; i++) {
		const current = nums[i];
		const needed = target - current;

		const matchIndex = indexByValue.get(needed);
		if (matchIndex !== undefined) {
			return [matchIndex, i];
		}

		indexByValue.set(current, i);
	}

	return null;
}

export function unionFindConnectedComponentsOnline(
	n: number,
	operations: readonly (readonly [number, number])[],
): number[] {
	const parent: number[] = Array.from({ length: n }, (_, i) => i);
	const rank: number[] = new Array(n).fill(0);
	let components = n;
	const result: number[] = [];

	const find = (x: number): number => {
		let root = x;
		while (parent[root] !== root) root = parent[root];
		while (parent[x] !== x) {
			const p = parent[x];
			parent[x] = root;
			x = p;
		}
		return root;
	};

	const union = (a: number, b: number): boolean => {
		let ra = find(a);
		let rb = find(b);
		if (ra === rb) return false;

		if (rank[ra] < rank[rb]) {
			[ra, rb] = [rb, ra];
		}
		parent[rb] = ra;
		if (rank[ra] === rank[rb]) rank[ra]++;
		return true;
	};

	for (const [u, v] of operations) {
		if (union(u, v)) components--;
		result.push(components);
	}

	return result;
}

export function validParentheses(input: string): boolean {
	const stack: string[] = [];
	const matching: Record<string, string> = {
		')': '(',
		']': '[',
		'}': '{',
	};

	for (const ch of input) {
		if (ch === '(' || ch === '[' || ch === '{') {
			stack.push(ch);
		} else if (ch === ')' || ch === ']' || ch === '}') {
			const top = stack.pop();
			if (top !== matching[ch]) return false;
		}
	}

	return stack.length === 0;
}

