type AVLNode = { value: number; height: number; left: AVLNode | null; right: AVLNode | null };

function height(node: AVLNode | null): number {
	return node ? node.height : 0;
}

function updateHeight(node: AVLNode): void {
	node.height = Math.max(height(node.left), height(node.right)) + 1;
}

function balanceFactor(node: AVLNode): number {
	return height(node.left) - height(node.right);
}

function rotateRight(y: AVLNode): AVLNode {
	const x = y.left as AVLNode;
	const t2 = x.right;

	x.right = y;
	y.left = t2;

	updateHeight(y);
	updateHeight(x);

	return x;
}

function rotateLeft(x: AVLNode): AVLNode {
	const y = x.right as AVLNode;
	const t2 = y.left;

	y.left = x;
	x.right = t2;

	updateHeight(x);
	updateHeight(y);

	return y;
}

function rebalance(node: AVLNode): AVLNode {
	updateHeight(node);
	const bf = balanceFactor(node);

	if (bf > 1) {
		if (balanceFactor(node.left as AVLNode) < 0) {
			node.left = rotateLeft(node.left as AVLNode);
		}
		return rotateRight(node);
	}

	if (bf < -1) {
		if (balanceFactor(node.right as AVLNode) > 0) {
			node.right = rotateRight(node.right as AVLNode);
		}
		return rotateLeft(node);
	}

	return node;
}

function insert(node: AVLNode | null, value: number): AVLNode {
	if (node === null) {
		return { value, height: 1, left: null, right: null };
	}

	if (value < node.value) {
		node.left = insert(node.left, value);
	} else if (value > node.value) {
		node.right = insert(node.right, value);
	} else {
		return node;
	}

	return rebalance(node);
}

export function avlTreeInsertRebalance(values: number[]): { value: number; height: number; left: any; right: any } | null {
	let root: AVLNode | null = null;

	for (const v of values) {
		root = insert(root, v);
	}

	return root;
}

class BStarNode {
	keys: number[] = [];
	children: BStarNode[] = [];
	leaf: boolean;

	constructor(leaf: boolean) {
		this.leaf = leaf;
	}
}

export function createBStarTree(t: number): {
	insert: (key: number) => void;
	search: (key: number) => boolean;
	delete: (key: number) => void;
	keys: () => number[];
} {
	if (!Number.isInteger(t) || t < 2) {
		throw new Error("t must be an integer >= 2");
	}

	const maxKeys = 2 * t - 1;
	const minKeys = t - 1;

	let root = new BStarNode(true);

	function findKey(node: BStarNode, key: number): number {
		let idx = 0;
		while (idx < node.keys.length && node.keys[idx] < key) idx++;
		return idx;
	}

	function searchNode(node: BStarNode, key: number): boolean {
		const i = findKey(node, key);
		if (i < node.keys.length && node.keys[i] === key) return true;
		if (node.leaf) return false;
		return searchNode(node.children[i], key);
	}

	function rotateFromLeft(parent: BStarNode, i: number): boolean {
		if (i <= 0) return false;
		const child = parent.children[i];
		const left = parent.children[i - 1];
		if (left.keys.length >= maxKeys) {
			child.keys.unshift(parent.keys[i - 1]);
			parent.keys[i - 1] = left.keys.pop() as number;
			if (!left.leaf) {
				child.children.unshift(left.children.pop() as BStarNode);
			}
			return true;
		}
		return false;
	}

	function rotateFromRight(parent: BStarNode, i: number): boolean {
		if (i >= parent.children.length - 1) return false;
		const child = parent.children[i];
		const right = parent.children[i + 1];
		if (right.keys.length >= maxKeys) {
			child.keys.push(parent.keys[i]);
			parent.keys[i] = right.keys.shift() as number;
			if (!right.leaf) {
				child.children.push(right.children.shift() as BStarNode);
			}
			return true;
		}
		return false;
	}

	function splitChild(parent: BStarNode, i: number): void {
		const y = parent.children[i];
		const z = new BStarNode(y.leaf);

		const mid = t - 1;
		const upKey = y.keys[mid];

		z.keys = y.keys.slice(mid + 1);
		y.keys = y.keys.slice(0, mid);

		if (!y.leaf) {
			z.children = y.children.slice(mid + 1);
			y.children = y.children.slice(0, mid + 1);
		}

		parent.children.splice(i + 1, 0, z);
		parent.keys.splice(i, 0, upKey);
	}

	function ensureChildSpaceBeforeInsert(parent: BStarNode, i: number): number {
		let idx = i;
		const child = parent.children[idx];
		if (child.keys.length < maxKeys) return idx;

		if (idx > 0 && parent.children[idx - 1].keys.length < maxKeys) {
			const left = parent.children[idx - 1];
			left.keys.push(parent.keys[idx - 1]);
			parent.keys[idx - 1] = child.keys.shift() as number;
			if (!child.leaf) {
				left.children.push(child.children.shift() as BStarNode);
			}
			return idx;
		}

		if (idx < parent.children.length - 1 && parent.children[idx + 1].keys.length < maxKeys) {
			const right = parent.children[idx + 1];
			right.keys.unshift(parent.keys[idx]);
			parent.keys[idx] = child.keys.pop() as number;
			if (!child.leaf) {
				right.children.unshift(child.children.pop() as BStarNode);
			}
			return idx;
		}

		splitChild(parent, idx);
		return idx;
	}

	function insertNonFull(node: BStarNode, key: number): void {
		let i = node.keys.length - 1;

		if (node.leaf) {
			node.keys.push(0);
			while (i >= 0 && node.keys[i] > key) {
				node.keys[i + 1] = node.keys[i];
				i--;
			}
			node.keys[i + 1] = key;
			return;
		}

		while (i >= 0 && node.keys[i] > key) i--;
		i++;

		i = ensureChildSpaceBeforeInsert(node, i);

		if (node.keys[i] < key) i++;
		insertNonFull(node.children[i], key);
	}

	function getPredecessor(node: BStarNode): number {
		let cur = node;
		while (!cur.leaf) cur = cur.children[cur.children.length - 1];
		return cur.keys[cur.keys.length - 1];
	}

	function getSuccessor(node: BStarNode): number {
		let cur = node;
		while (!cur.leaf) cur = cur.children[0];
		return cur.keys[0];
	}

	function merge(parent: BStarNode, idx: number): void {
		const child = parent.children[idx];
		const sibling = parent.children[idx + 1];

		child.keys.push(parent.keys[idx], ...sibling.keys);
		if (!child.leaf) {
			child.children.push(...sibling.children);
		}

		parent.keys.splice(idx, 1);
		parent.children.splice(idx + 1, 1);
	}

	function fill(parent: BStarNode, idx: number): void {
		if (idx > 0 && parent.children[idx - 1].keys.length > minKeys) {
			const child = parent.children[idx];
			const left = parent.children[idx - 1];

			child.keys.unshift(parent.keys[idx - 1]);
			parent.keys[idx - 1] = left.keys.pop() as number;
			if (!left.leaf) {
				child.children.unshift(left.children.pop() as BStarNode);
			}
		} else if (idx < parent.children.length - 1 && parent.children[idx + 1].keys.length > minKeys) {
			const child = parent.children[idx];
			const right = parent.children[idx + 1];

			child.keys.push(parent.keys[idx]);
			parent.keys[idx] = right.keys.shift() as number;
			if (!right.leaf) {
				child.children.push(right.children.shift() as BStarNode);
			}
		} else {
			if (idx < parent.children.length - 1) {
				merge(parent, idx);
			} else {
				merge(parent, idx - 1);
			}
		}
	}

	function deleteFromNode(node: BStarNode, key: number): void {
		const idx = findKey(node, key);

		if (idx < node.keys.length && node.keys[idx] === key) {
			if (node.leaf) {
				node.keys.splice(idx, 1);
				return;
			}

			if (node.children[idx].keys.length > minKeys) {
				const pred = getPredecessor(node.children[idx]);
				node.keys[idx] = pred;
				deleteFromNode(node.children[idx], pred);
			} else if (node.children[idx + 1].keys.length > minKeys) {
				const succ = getSuccessor(node.children[idx + 1]);
				node.keys[idx] = succ;
				deleteFromNode(node.children[idx + 1], succ);
			} else {
				merge(node, idx);
				deleteFromNode(node.children[idx], key);
			}
		} else {
			if (node.leaf) return;

			let childIdx = idx;
			if (node.children[childIdx].keys.length === minKeys) {
				fill(node, childIdx);
				if (childIdx > node.keys.length) childIdx--;
			}
			deleteFromNode(node.children[childIdx], key);
		}
	}

	function inorder(node: BStarNode, out: number[]): void {
		for (let i = 0; i < node.keys.length; i++) {
			if (!node.leaf) inorder(node.children[i], out);
			out.push(node.keys[i]);
		}
		if (!node.leaf) inorder(node.children[node.keys.length], out);
	}

	return {
		insert: (key: number) => {
			if (!Number.isFinite(key)) throw new Error("key must be a finite number");
			if (searchNode(root, key)) return;

			if (root.keys.length === maxKeys) {
				const s = new BStarNode(false);
				s.children.push(root);
				splitChild(s, 0);
				root = s;
			}
			insertNonFull(root, key);
		},
		search: (key: number) => {
			if (!Number.isFinite(key)) return false;
			return searchNode(root, key);
		},
		delete: (key: number) => {
			if (!Number.isFinite(key)) return;
			if (!searchNode(root, key)) return;

			deleteFromNode(root, key);

			if (!root.leaf && root.keys.length === 0) {
				root = root.children[0];
			}
		},
		keys: () => {
			const out: number[] = [];
			inorder(root, out);
			return out;
		},
	};
}

type BTreeNode = {
	keys: number[];
	children: BTreeNode[];
	leaf: boolean;
};

export function createBTree(t: number): {
	insert: (key: number) => void;
	search: (key: number) => boolean;
	delete: (key: number) => void;
	keys: () => number[];
} {
	if (!Number.isInteger(t) || t < 2) {
		throw new Error("Minimum degree t must be an integer >= 2");
	}

	let root: BTreeNode = { keys: [], children: [], leaf: true };

	function searchNode(node: BTreeNode, key: number): { node: BTreeNode; idx: number } | null {
		let i = 0;
		while (i < node.keys.length && key > node.keys[i]) i++;
		if (i < node.keys.length && node.keys[i] === key) return { node, idx: i };
		if (node.leaf) return null;
		return searchNode(node.children[i], key);
	}

	function splitChild(parent: BTreeNode, i: number): void {
		const y = parent.children[i];
		const z: BTreeNode = { keys: [], children: [], leaf: y.leaf };

		const midKey = y.keys[t - 1];

		z.keys = y.keys.slice(t);
		y.keys = y.keys.slice(0, t - 1);

		if (!y.leaf) {
			z.children = y.children.slice(t);
			y.children = y.children.slice(0, t);
		}

		parent.children.splice(i + 1, 0, z);
		parent.keys.splice(i, 0, midKey);
	}

	function insertNonFull(node: BTreeNode, key: number): void {
		let i = node.keys.length - 1;

		if (node.leaf) {
			while (i >= 0 && key < node.keys[i]) i--;
			if (i >= 0 && node.keys[i] === key) return;
			if (i + 1 < node.keys.length && node.keys[i + 1] === key) return;
			node.keys.splice(i + 1, 0, key);
			return;
		}

		while (i >= 0 && key < node.keys[i]) i--;
		i++;

		if (node.children[i].keys.length === 2 * t - 1) {
			splitChild(node, i);
			if (key === node.keys[i]) return;
			if (key > node.keys[i]) i++;
		}
		insertNonFull(node.children[i], key);
	}

	function findKey(node: BTreeNode, key: number): number {
		let idx = 0;
		while (idx < node.keys.length && node.keys[idx] < key) idx++;
		return idx;
	}

	function getPredecessor(node: BTreeNode): number {
		let cur = node;
		while (!cur.leaf) cur = cur.children[cur.children.length - 1];
		return cur.keys[cur.keys.length - 1];
	}

	function getSuccessor(node: BTreeNode): number {
		let cur = node;
		while (!cur.leaf) cur = cur.children[0];
		return cur.keys[0];
	}

	function merge(node: BTreeNode, idx: number): void {
		const child = node.children[idx];
		const sibling = node.children[idx + 1];

		child.keys.push(node.keys[idx], ...sibling.keys);
		if (!child.leaf) child.children.push(...sibling.children);

		node.keys.splice(idx, 1);
		node.children.splice(idx + 1, 1);
	}

	function borrowFromPrev(node: BTreeNode, idx: number): void {
		const child = node.children[idx];
		const sibling = node.children[idx - 1];

		child.keys.unshift(node.keys[idx - 1]);
		if (!child.leaf) {
			const movedChild = sibling.children.pop();
			if (movedChild) child.children.unshift(movedChild);
		}
		node.keys[idx - 1] = sibling.keys.pop() as number;
	}

	function borrowFromNext(node: BTreeNode, idx: number): void {
		const child = node.children[idx];
		const sibling = node.children[idx + 1];

		child.keys.push(node.keys[idx]);
		if (!child.leaf) {
			const movedChild = sibling.children.shift();
			if (movedChild) child.children.push(movedChild);
		}
		node.keys[idx] = sibling.keys.shift() as number;
	}

	function fill(node: BTreeNode, idx: number): void {
		if (idx > 0 && node.children[idx - 1].keys.length >= t) {
			borrowFromPrev(node, idx);
		} else if (idx < node.children.length - 1 && node.children[idx + 1].keys.length >= t) {
			borrowFromNext(node, idx);
		} else {
			if (idx < node.children.length - 1) merge(node, idx);
			else merge(node, idx - 1);
		}
	}

	function removeFromNonLeaf(node: BTreeNode, idx: number): void {
		const key = node.keys[idx];

		if (node.children[idx].keys.length >= t) {
			const pred = getPredecessor(node.children[idx]);
			node.keys[idx] = pred;
			remove(node.children[idx], pred);
		} else if (node.children[idx + 1].keys.length >= t) {
			const succ = getSuccessor(node.children[idx + 1]);
			node.keys[idx] = succ;
			remove(node.children[idx + 1], succ);
		} else {
			merge(node, idx);
			remove(node.children[idx], key);
		}
	}

	function remove(node: BTreeNode, key: number): void {
		const idx = findKey(node, key);

		if (idx < node.keys.length && node.keys[idx] === key) {
			if (node.leaf) {
				node.keys.splice(idx, 1);
			} else {
				removeFromNonLeaf(node, idx);
			}
			return;
		}

		if (node.leaf) return;

		const flag = idx === node.keys.length;

		if (node.children[idx].keys.length < t) {
			fill(node, idx);
		}

		if (flag && idx > node.keys.length) {
			remove(node.children[idx - 1], key);
		} else {
			remove(node.children[idx], key);
		}
	}

	function inorder(node: BTreeNode, out: number[]): void {
		for (let i = 0; i < node.keys.length; i++) {
			if (!node.leaf) inorder(node.children[i], out);
			out.push(node.keys[i]);
		}
		if (!node.leaf) inorder(node.children[node.keys.length], out);
	}

	return {
		insert: (key: number) => {
			if (searchNode(root, key)) return;

			if (root.keys.length === 2 * t - 1) {
				const s: BTreeNode = { keys: [], children: [root], leaf: false };
				splitChild(s, 0);
				root = s;
			}
			insertNonFull(root, key);
		},
		search: (key: number) => searchNode(root, key) !== null,
		delete: (key: number) => {
			if (!root) return;
			remove(root, key);

			if (root.keys.length === 0) {
				if (root.leaf) {
					root = { keys: [], children: [], leaf: true };
				} else {
					root = root.children[0];
				}
			}
		},
		keys: () => {
			const out: number[] = [];
			inorder(root, out);
			return out;
		},
	};
}

export function bloomFilterNHashFunctions(
	size: number,
	hashCount: number,
	wordsToAdd: string[],
	queries: string[]
): boolean[] {
	const bitArray: boolean[] = new Array(Math.max(0, size)).fill(false);

	const fnv1a32 = (str: string, seed: number): number => {
		let hash = (0x811c9dc5 ^ seed) >>> 0;
		for (let i = 0; i < str.length; i++) {
			hash ^= str.charCodeAt(i);
			hash = Math.imul(hash, 0x01000193) >>> 0;
		}
		return hash >>> 0;
	};

	const getIndices = (word: string): number[] => {
		if (size <= 0 || hashCount <= 0) return [];
		const h1 = fnv1a32(word, 0);
		const h2 = fnv1a32(word, 0x9e3779b9) | 1; // ensure odd/non-zero step
		const indices: number[] = new Array(hashCount);
		for (let i = 0; i < hashCount; i++) {
			const combined = (h1 + Math.imul(i, h2)) >>> 0;
			indices[i] = combined % size;
		}
		return indices;
	};

	for (const word of wordsToAdd) {
		const indices = getIndices(word);
		for (const idx of indices) bitArray[idx] = true;
	}

	const result: boolean[] = [];
	for (const query of queries) {
		const indices = getIndices(query);
		let possiblyPresent = true;
		for (const idx of indices) {
			if (!bitArray[idx]) {
				possiblyPresent = false;
				break;
			}
		}
		result.push(possiblyPresent);
	}

	return result;
}

export function detectCycleDirectedGraph(graph: Record<number, number[]>): boolean {
	const visiting = new Set<number>();
	const visited = new Set<number>();

	const allNodes = new Set<number>();
	for (const key of Object.keys(graph)) {
		const node = Number(key);
		allNodes.add(node);
		for (const neighbor of graph[node] ?? []) {
			allNodes.add(neighbor);
		}
	}

	function dfs(node: number): boolean {
		if (visiting.has(node)) return true;
		if (visited.has(node)) return false;

		visiting.add(node);
		for (const neighbor of graph[node] ?? []) {
			if (dfs(neighbor)) return true;
		}
		visiting.delete(node);
		visited.add(node);
		return false;
	}

	for (const node of allNodes) {
		if (!visited.has(node) && dfs(node)) return true;
	}

	return false;
}

export function evaluateReversePolishNotation(tokens: string[]): number {
	const stack: number[] = [];

	for (const token of tokens) {
		if (token === "+" || token === "-" || token === "*" || token === "/") {
			const b = stack.pop();
			const a = stack.pop();

			if (a === undefined || b === undefined) {
				throw new Error("Invalid RPN expression");
			}

			let result: number;
			switch (token) {
				case "+":
					result = a + b;
					break;
				case "-":
					result = a - b;
					break;
				case "*":
					result = a * b;
					break;
				case "/":
					result = Math.trunc(a / b);
					break;
				default:
					throw new Error("Unsupported operator");
			}
			stack.push(result);
		} else {
			const value = Number(token);
			if (Number.isNaN(value)) {
				throw new Error("Invalid token");
			}
			stack.push(value);
		}
	}

	if (stack.length !== 1) {
		throw new Error("Invalid RPN expression");
	}

	return stack[0];
}

export function kLargestElementsInStream(stream: number[], k: number): number[][] {
	const result: number[][] = [];

	if (k <= 0) {
		for (let i = 0; i < stream.length; i++) result.push([]);
		return result;
	}

	const top: number[] = [];

	for (const value of stream) {
		let insertPos = 0;
		while (insertPos < top.length && top[insertPos] > value) {
			insertPos++;
		}
		top.splice(insertPos, 0, value);

		if (top.length > k) {
			top.pop();
		}

		result.push([...top]);
	}

	return result;
}

export function reverseLinkedListInPlace(
	head: { value: number; next: any } | null
): { value: number; next: any } | null {
	let prev: { value: number; next: any } | null = null;
	let current = head;

	while (current !== null) {
		const next = current.next;
		current.next = prev;
		prev = current;
		current = next;
	}

	return prev;
}

export function trieAutocomplete(words: string[], prefixes: string[]): string[][] {
	type Node = {
		children: Map<string, Node>;
		isWord: boolean;
	};

	const root: Node = { children: new Map(), isWord: false };

	for (const word of words) {
		let node = root;
		for (const ch of word) {
			let next = node.children.get(ch);
			if (!next) {
				next = { children: new Map(), isWord: false };
				node.children.set(ch, next);
			}
			node = next;
		}
		node.isWord = true;
	}

	function collect(node: Node, path: string, out: string[]): void {
		if (node.isWord) out.push(path);
		const keys = Array.from(node.children.keys()).sort();
		for (const k of keys) {
			collect(node.children.get(k) as Node, path + k, out);
		}
	}

	const result: string[][] = [];

	for (const prefix of prefixes) {
		let node: Node | undefined = root;
		for (const ch of prefix) {
			node = node.children.get(ch);
			if (!node) break;
		}

		if (!node) {
			result.push([]);
			continue;
		}

		const matches: string[] = [];
		collect(node, prefix, matches);
		result.push(matches);
	}

	return result;
}

export function validateBinarySearchTree(
	root: { value: number; left: any; right: any } | null,
): boolean {
	function isValid(
		node: { value: number; left: any; right: any } | null,
		min: number,
		max: number,
	): boolean {
		if (node === null) return true;
		if (node.value <= min || node.value >= max) return false;
		return isValid(node.left, min, node.value) && isValid(node.right, node.value, max);
	}

	return isValid(root, -Infinity, Infinity);
}

export function easterSunday(year: number): { month: number; day: number } {
	const a = year % 19;
	const b = Math.floor(year / 100);
	const c = year % 100;
	const d = Math.floor(b / 4);
	const e = b % 4;
	const f = Math.floor((b + 8) / 25);
	const g = Math.floor((b - f + 1) / 3);
	const h = (19 * a + b - d - g + 15) % 30;
	const i = Math.floor(c / 4);
	const k = c % 4;
	const l = (32 + 2 * e + 2 * i - h - k) % 7;
	const m = Math.floor((a + 11 * h + 22 * l) / 451);
	const month = Math.floor((h + l - 7 * m + 114) / 31);
	const day = ((h + l - 7 * m + 114) % 31) + 1;

	return { month, day };
}

export function getISOWeek(date: Date): { week: number; year: number } {
	const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
	const day = d.getUTCDay() || 7;
	d.setUTCDate(d.getUTCDate() + 4 - day);

	const year = d.getUTCFullYear();
	const yearStart = new Date(Date.UTC(year, 0, 1));
	const week = Math.ceil(((d.getTime() - yearStart.getTime()) / 86400000 + 1) / 7);

	return { week, year };
}

export function validateDate(s: string): boolean {
	const match = /^(\d{4})-(\d{2})-(\d{2})$/.exec(s);
	if (!match) return false;

	const year = Number(match[1]);
	const month = Number(match[2]);
	const day = Number(match[3]);

	if (month < 1 || month > 12) return false;

	const isLeapYear =
		(year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;

	const daysInMonth = [31, isLeapYear ? 29 : 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
	const maxDay = daysInMonth[month - 1];

	return day >= 1 && day <= maxDay;
}

export const html06DialogModal = (): string => {
	return `<!doctype html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Accessible Dialog Modal</title>
  <style>
    body { font-family: Arial, sans-serif; padding: 2rem; }
    dialog { border: none; border-radius: 8px; padding: 1rem 1.25rem; max-width: 420px; width: 100%; }
    dialog::backdrop { background: rgba(0,0,0,0.45); }
    .dialog-header { display: flex; justify-content: space-between; align-items: center; gap: 1rem; }
    .close-btn { border: none; background: transparent; font-size: 1.1rem; cursor: pointer; }
    .actions { margin-top: 1rem; display: flex; gap: 0.5rem; justify-content: flex-end; }
  </style>
</head>
<body>
  <button id="open-dialog" type="button">Open modal</button>

  <dialog id="modal" aria-labelledby="dialog-title" aria-describedby="dialog-description">
    <div class="dialog-header">
      <h2 id="dialog-title">Confirm action</h2>
      <button id="close-dialog-top" class="close-btn" type="button" aria-label="Close dialog">✕</button>
    </div>
    <p id="dialog-description">This is an accessible modal built with the native dialog element.</p>
    <div class="actions">
      <button id="cancel-btn" type="button">Cancel</button>
      <button id="confirm-btn" type="button">Confirm</button>
    </div>
  </dialog>

  <script>
    const dialog = document.getElementById('modal');
    const openBtn = document.getElementById('open-dialog');
    const closeTopBtn = document.getElementById('close-dialog-top');
    const cancelBtn = document.getElementById('cancel-btn');
    const confirmBtn = document.getElementById('confirm-btn');

    const getFocusable = () => {
      return Array.from(
        dialog.querySelectorAll(
          'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        )
      ).filter(el => !el.hasAttribute('disabled'));
    };

    const closeDialog = () => {
      if (dialog.open) dialog.close();
      openBtn.focus();
    };

    openBtn.addEventListener('click', () => {
      dialog.showModal();
      const focusable = getFocusable();
      const first = focusable[0];
      first?.focus();
    });

    closeTopBtn.addEventListener('click', closeDialog);
    cancelBtn.addEventListener('click', closeDialog);
    confirmBtn.addEventListener('click', closeDialog);

    dialog.addEventListener('click', (event) => {
      if (event.target === dialog) {
        closeDialog();
      }
    });

    dialog.addEventListener('keydown', (event) => {
      if (event.key === 'Escape') {
        event.preventDefault();
        closeDialog();
        return;
      }

      if (event.key !== 'Tab') return;

      const focusable = getFocusable();
      if (focusable.length === 0) return;

      const first = focusable[0];
      const last = focusable[focusable.length - 1];
      const active = document.activeElement;

      if (event.shiftKey && active === first) {
        event.preventDefault();
        last?.focus();
      } else if (!event.shiftKey && active === last) {
        event.preventDefault();
        first?.focus();
      }
    });
  </script>
</body>
</html>`;
};

