export type Row = Record<string, string | number | boolean | null>;

function isValidXmlName(name: string): boolean {
	return /^[A-Za-z_][A-Za-z0-9._-]*$/.test(name);
}

function assertValidXmlName(name: string, label: string): void {
	if (!name || !isValidXmlName(name)) {
		throw new Error(`Invalid ${label}: "${name}"`);
	}
}

function escapeCsvField(value: string): string {
	if (/[",\r\n]/.test(value)) {
		return `"${value.replace(/"/g, '""')}"`;
	}
	return value;
}

function parseCsv(csv: string): string[][] {
	if (typeof csv !== 'string') {
		throw new Error('CSV input must be a string');
	}
	const rows: string[][] = [];
	let row: string[] = [];
	let field = '';
	let i = 0;
	let inQuotes = false;

	while (i < csv.length) {
		const ch = csv[i];

		if (inQuotes) {
			if (ch === '"') {
				if (i + 1 < csv.length && csv[i + 1] === '"') {
					field += '"';
					i += 2;
				} else {
					inQuotes = false;
					i++;
				}
			} else {
				field += ch;
				i++;
			}
		} else {
			if (ch === '"') {
				if (field.length !== 0) {
					throw new Error('Invalid CSV: unexpected quote in unquoted field');
				}
				inQuotes = true;
				i++;
			} else if (ch === ',') {
				row.push(field);
				field = '';
				i++;
			} else if (ch === '\n') {
				row.push(field);
				rows.push(row);
				row = [];
				field = '';
				i++;
			} else if (ch === '\r') {
				row.push(field);
				rows.push(row);
				row = [];
				field = '';
				if (i + 1 < csv.length && csv[i + 1] === '\n') {
					i += 2;
				} else {
					i++;
				}
			} else {
				field += ch;
				i++;
			}
		}
	}

	if (inQuotes) {
		throw new Error('Invalid CSV: unterminated quoted field');
	}

	row.push(field);
	if (!(rows.length === 0 && row.length === 1 && row[0] === '')) {
		rows.push(row);
	}

	return rows;
}

function inferValue(raw: string): string | number | boolean | null {
	const v = raw.trim();
	if (v === '') return '';
	if (v === 'null') return null;
	if (v === 'true') return true;
	if (v === 'false') return false;
	if (/^[+-]?(?:\d+\.?\d*|\.\d+)(?:[eE][+-]?\d+)?$/.test(v)) {
		const n = Number(v);
		if (!Number.isNaN(n)) return n;
	}
	return raw;
}

function valueToString(value: string | number | boolean | null): string {
	if (value === null) return 'null';
	return String(value);
}

function escapeXmlText(text: string): string {
	return text
		.replace(/&/g, '&amp;')
		.replace(/</g, '&lt;')
		.replace(/>/g, '&gt;')
		.replace(/"/g, '&quot;')
		.replace(/'/g, '&apos;');
}

function unescapeXmlText(text: string): string {
	return text
		.replace(/&lt;/g, '<')
		.replace(/&gt;/g, '>')
		.replace(/&quot;/g, '"')
		.replace(/&apos;/g, "'")
		.replace(/&amp;/g, '&');
}

function stripXmlDeclarationAndComments(xml: string): string {
	return xml
		.replace(/^\s*<\?xml[\s\S]*?\?>\s*/i, '')
		.replace(/<!--[\s\S]*?-->/g, '')
		.trim();
}

function parseSimpleRowsXml(xml: string, rowElement: string): Row[] {
	const clean = stripXmlDeclarationAndComments(xml);
	if (!clean) return [];

	const rowRegex = new RegExp(`<${rowElement}>([\\s\\S]*?)<\\/${rowElement}>`, 'g');
	const rows: Row[] = [];
	let rowMatch: RegExpExecArray | null;

	while ((rowMatch = rowRegex.exec(clean)) !== null) {
		const rowContent = rowMatch[1];
		const row: Row = {};
		const fieldRegex = /<([A-Za-z_][A-Za-z0-9._-]*)>([\s\S]*?)<\/\1>/g;
		let fieldMatch: RegExpExecArray | null;
		let consumed = '';

		while ((fieldMatch = fieldRegex.exec(rowContent)) !== null) {
			const key = fieldMatch[1];
			const raw = unescapeXmlText(fieldMatch[2]);
			row[key] = inferValue(raw);
			consumed += fieldMatch[0];
		}

		if (rowContent.replace(/\s+/g, '') !== consumed.replace(/\s+/g, '')) {
			throw new Error('Invalid XML: unsupported nested structure inside row element');
		}
		rows.push(row);
	}

	if (rows.length === 0) {
		const stripped = clean.replace(/\s+/g, '');
		if (stripped !== '') {
			throw new Error(`Invalid XML: no <${rowElement}> elements found`);
		}
	}

	return rows;
}

export function jsonToCsv(rows: Row[]): string {
	if (!Array.isArray(rows)) {
		throw new Error('Input rows must be an array');
	}
	if (rows.length === 0) return '';

	const headerSet = new Set<string>();
	for (const row of rows) {
		if (!row || typeof row !== 'object' || Array.isArray(row)) {
			throw new Error('Each row must be an object');
		}
		for (const k of Object.keys(row)) headerSet.add(k);
	}
	const headers = Array.from(headerSet);
	const lines: string[] = [];
	lines.push(headers.map(escapeCsvField).join(','));

	for (const row of rows) {
		const line = headers
			.map((h) => escapeCsvField(valueToString((row as Row)[h] ?? null)))
			.join(',');
		lines.push(line);
	}
	return lines.join('\n');
}

export function csvToJson(csv: string): Row[] {
	const data = parseCsv(csv);
	if (data.length === 0) return [];
	const header = data[0];
	if (header.length === 0 || header.every((h) => h.trim() === '')) {
		throw new Error('Invalid CSV: header row is missing');
	}
	const unique = new Set(header);
	if (unique.size !== header.length) {
		throw new Error('Invalid CSV: duplicate header names');
	}

	const rows: Row[] = [];
	for (let i = 1; i < data.length; i++) {
		const rec = data[i];
		if (rec.length !== header.length) {
			throw new Error(`Invalid CSV: row ${i + 1} has ${rec.length} fields, expected ${header.length}`);
		}
		const row: Row = {};
		for (let j = 0; j < header.length; j++) {
			row[header[j]] = inferValue(rec[j]);
		}
		rows.push(row);
	}
	return rows;
}

export function jsonToXml(rows: Row[], rootElement: string, rowElement: string): string {
	if (!Array.isArray(rows)) {
		throw new Error('Input rows must be an array');
	}
	assertValidXmlName(rootElement, 'rootElement');
	assertValidXmlName(rowElement, 'rowElement');

	const parts: string[] = [];
	parts.push(`<${rootElement}>`);
	for (const row of rows) {
		if (!row || typeof row !== 'object' || Array.isArray(row)) {
			throw new Error('Each row must be an object');
		}
		parts.push(`<${rowElement}>`);
		for (const key of Object.keys(row)) {
			assertValidXmlName(key, 'field name');
			const val = valueToString(row[key]);
			parts.push(`<${key}>${escapeXmlText(val)}</${key}>`);
		}
		parts.push(`</${rowElement}>`);
	}
	parts.push(`</${rootElement}>`);
	return parts.join('');
}

export function xmlToJson(xml: string, rowElement: string): Row[] {
	if (typeof xml !== 'string') {
		throw new Error('XML input must be a string');
	}
	assertValidXmlName(rowElement, 'rowElement');
	return parseSimpleRowsXml(xml, rowElement);
}

export function csvToXml(csv: string, rootElement: string, rowElement: string): string {
	const rows = csvToJson(csv);
	return jsonToXml(rows, rootElement, rowElement);
}

export function xmlToCsv(xml: string, rowElement: string): string {
	const rows = xmlToJson(xml, rowElement);
	return jsonToCsv(rows);
}

export function normalizeNumberInput(input: string | number | null): number | null {
	if (input === null) return null;

	if (typeof input === 'number') {
		return Number.isFinite(input) ? input : null;
	}

	const trimmed = input.trim();
	if (trimmed === '') return null;

	const parsed = Number(trimmed);
	return Number.isFinite(parsed) ? parsed : null;
}

