export function queryParamCoercion(query: string): { page: number; limit: number; includeArchived: boolean } {
	const result = {
		page: 1,
		limit: 20,
		includeArchived: false,
	};

	const normalized = query.startsWith("?") ? query.slice(1) : query;
	const params = new URLSearchParams(normalized);

	const pageRaw = params.get("page");
	if (pageRaw !== null) {
		const pageNum = Number(pageRaw);
		if (Number.isInteger(pageNum) && pageNum > 0) {
			result.page = pageNum;
		}
	}

	const limitRaw = params.get("limit");
	if (limitRaw !== null) {
		const limitNum = Number(limitRaw);
		if (Number.isInteger(limitNum) && limitNum > 0) {
			result.limit = limitNum;
		}
	}

	const archivedRaw = params.get("includeArchived");
	if (archivedRaw !== null) {
		const v = archivedRaw.trim().toLowerCase();
		if (v === "true" || v === "1") {
			result.includeArchived = true;
		} else if (v === "false" || v === "0") {
			result.includeArchived = false;
		}
	}

	return result;
}

