export function fibonacci(n: number): number {
	const memo = new Map<number, number>([
		[0, 0],
		[1, 1],
	]);

	function fib(x: number): number {
		const cached = memo.get(x);
		if (cached !== undefined) {
			return cached;
		}
		const value = fib(x - 1) + fib(x - 2);
		memo.set(x, value);
		return value;
	}

	return fib(n);
}

