export function jaroWinkler(s1: string, s2: string): number {
	if (s1 === s2) return 1;

	const len1 = s1.length;
	const len2 = s2.length;

	if (len1 === 0 || len2 === 0) return 0;

	const matchDistance = Math.floor(Math.max(len1, len2) / 2) - 1;

	const s1Matches = new Array<boolean>(len1).fill(false);
	const s2Matches = new Array<boolean>(len2).fill(false);

	let matches = 0;
	for (let i = 0; i < len1; i++) {
		const start = Math.max(0, i - matchDistance);
		const end = Math.min(i + matchDistance + 1, len2);

		for (let j = start; j < end; j++) {
			if (s2Matches[j]) continue;
			if (s1[i] !== s2[j]) continue;
			s1Matches[i] = true;
			s2Matches[j] = true;
			matches++;
			break;
		}
	}

	if (matches === 0) return 0;

	let t = 0;
	let k = 0;
	for (let i = 0; i < len1; i++) {
		if (!s1Matches[i]) continue;
		while (!s2Matches[k]) k++;
		if (s1[i] !== s2[k]) t++;
		k++;
	}
	const transpositions = t / 2;

	const m = matches;
	const jaro = (m / len1 + m / len2 + (m - transpositions) / m) / 3;

	let prefix = 0;
	const maxPrefix = Math.min(4, len1, len2);
	for (let i = 0; i < maxPrefix; i++) {
		if (s1[i] === s2[i]) prefix++;
		else break;
	}

	const p = 0.1;
	const winkler = jaro + prefix * p * (1 - jaro);

	return Math.max(0, Math.min(1, winkler));
}

export type WrapOptions = {
	width?: number;
	lineBreak?: string;
	mode?: 'soft' | 'hard';
	hangingIndent?: string;
	collapseWhitespace?: boolean;
};

function normalizeWhitespace(input: string): string {
	return input.replace(/[ \t\r\f\v]+/g, ' ').trim();
}

function splitHard(segment: string, width: number): string[] {
	if (segment.length === 0) return [''];
	const out: string[] = [];
	for (let i = 0; i < segment.length; i += width) {
		out.push(segment.slice(i, i + width));
	}
	return out;
}

function wrapParagraph(
	paragraph: string,
	width: number,
	mode: 'soft' | 'hard',
	indent: string,
	collapseWhitespace: boolean
): string[] {
	const content = collapseWhitespace ? normalizeWhitespace(paragraph) : paragraph;
	if (content.length === 0) return [''];

	const lines: string[] = [];
	let current = '';
	let firstLine = true;

	const effectiveWidth = (isFirst: boolean): number =>
		Math.max(1, width - (isFirst ? 0 : indent.length));

	if (mode === 'hard') {
		const tokens = collapseWhitespace ? content.split(' ') : content.split(/(\s+)/).filter((t) => t.length > 0);

		for (const token of tokens) {
			const isSpace = /^\s+$/.test(token);
			if (isSpace) {
				if (collapseWhitespace) {
					if (current.length > 0 && !current.endsWith(' ')) current += ' ';
				} else {
					current += token;
				}
				continue;
			}

			const maxLen = effectiveWidth(firstLine);
			if (current.length === 0) {
				if (token.length <= maxLen) {
					current = token;
				} else {
					const parts = splitHard(token, maxLen);
					lines.push(...parts.slice(0, -1));
					current = parts[parts.length - 1];
					firstLine = false;
				}
			} else {
				const candidate = current + token;
				if (candidate.length <= maxLen) {
					current = candidate;
				} else {
					lines.push(current.replace(/\s+$/g, ''));
					firstLine = false;
					const nextMax = effectiveWidth(firstLine);
					if (token.length <= nextMax) {
						current = token;
					} else {
						const parts = splitHard(token, nextMax);
						lines.push(...parts.slice(0, -1));
						current = parts[parts.length - 1];
					}
				}
			}
		}

		if (current.length > 0 || lines.length === 0) {
			lines.push(current.replace(/\s+$/g, ''));
		}
	} else {
		const tokens = collapseWhitespace ? content.split(' ') : content.split(/(\s+)/).filter((t) => t.length > 0);

		for (const token of tokens) {
			const isSpace = /^\s+$/.test(token);

			if (isSpace) {
				if (collapseWhitespace) {
					if (current.length > 0 && !current.endsWith(' ')) current += ' ';
				} else {
					current += token;
				}
				continue;
			}

			const maxLen = effectiveWidth(firstLine);
			if (current.length === 0) {
				current = token;
			} else {
				const candidate = current + token;
				if (candidate.length <= maxLen) {
					current = candidate;
				} else {
					lines.push(current.replace(/\s+$/g, ''));
					firstLine = false;
					current = token;
				}
			}
		}

		if (current.length > 0 || lines.length === 0) {
			lines.push(current.replace(/\s+$/g, ''));
		}
	}

	return lines.map((line, idx) => (idx === 0 ? line : indent + line));
}

export function wordWrap(text: string, options?: WrapOptions): string {
	const width = Math.max(1, options?.width ?? 80);
	const lineBreak = options?.lineBreak ?? '\n';
	const mode: 'soft' | 'hard' = options?.mode ?? 'soft';
	const hangingIndent = options?.hangingIndent ?? '';
	const collapseWhitespace = options?.collapseWhitespace ?? false;

	const normalized = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
	const paragraphs = normalized.split('\n');

	const outLines: string[] = [];
	for (const paragraph of paragraphs) {
		const wrapped = wrapParagraph(paragraph, width, mode, hangingIndent, collapseWhitespace);
		outLines.push(...wrapped);
	}

	return outLines.join(lineBreak);
}

