export class LRUCache {
	#capacity;
	#map = new Map();

	constructor(capacity) {
		if (capacity <= 0) {
			throw new RangeError('capacity must be > 0');
		}
		this.#capacity = capacity;
	}

	get(key) {
		if (!this.#map.has(key)) {
			return undefined;
		}
		const value = this.#map.get(key);
		this.#map.delete(key);
		this.#map.set(key, value);
		return value;
	}

	set(key, value) {
		if (this.#map.has(key)) {
			this.#map.delete(key);
		} else if (this.#map.size >= this.#capacity) {
			this.#map.delete(this.#map.keys().next().value);
		}
		this.#map.set(key, value);
	}

	delete(key) {
		return this.#map.delete(key);
	}

	get size() {
		return this.#map.size;
	}
}

function log(target: object, key: string, descriptor: PropertyDescriptor): PropertyDescriptor {
	const original = descriptor.value as (...args: unknown[]) => unknown;
	descriptor.value = function (...args: unknown[]) {
		console.log(`[${key}] called with`, args);
		const result = original.apply(this, args);
		console.log(`[${key}] returned`, result);
		return result;
	};
	return descriptor;
}

class Calculator {
	add(a: number, b: number): number {
		return a + b;
	}
}

const addDescriptor = Object.getOwnPropertyDescriptor(Calculator.prototype, "add");
if (addDescriptor) {
	Object.defineProperty(Calculator.prototype, "add", log(Calculator.prototype, "add", addDescriptor));
}

export function area(shape) {
	switch (shape.kind) {
		case 'circle':
			return Math.PI * shape.radius ** 2;
		case 'rectangle':
			return shape.width * shape.height;
		case 'triangle':
			return 0.5 * shape.base * shape.height;
		default:
			throw new Error(`Unhandled shape: ${JSON.stringify(shape)}`);
	}
}

const Direction = {
	Up: 'UP',
	Down: 'DOWN',
	Left: 'LEFT',
	Right: 'RIGHT',
};

export function opposite(d) {
	switch (d) {
		case Direction.Up:
			return Direction.Down;
		case Direction.Down:
			return Direction.Up;
		case Direction.Left:
			return Direction.Right;
		case Direction.Right:
			return Direction.Left;
	}
}

export function mergeDeep(target, source) {
	const result = { ...target };
	for (const key in source) {
		const s = source[key];
		const t = target[key];
		if (s && typeof s === 'object' && !Array.isArray(s)) {
			result[key] = mergeDeep(t && typeof t === 'object' && !Array.isArray(t) ? t : {}, s);
		} else if (s !== undefined) {
			result[key] = s;
		}
	}
	return result;
}

export function stripNulls(obj) {
	return Object.fromEntries(
		Object.entries(obj).filter(([, v]) => v !== null)
	);
}

export function requireRole(role) {
	return (req, res, next) => {
		if (!req.user?.roles.includes(role)) {
			res.status(403).json({error: 'Forbidden'});
			return;
		}
		next();
	};
}

export function format(value: number | Date | number[]): string | string[] {
	if (Array.isArray(value)) {
		return value.map((n) => n.toFixed(2));
	}
	if (value instanceof Date) {
		return value.toISOString().slice(0, 10);
	}
	return value.toFixed(2);
}

function createSchema(parse) {
	return {
		parse,
		optional() {
			return optional(this);
		},
		nullable() {
			return nullable(this);
		},
	};
}

function string() {
	return createSchema((input) => {
		if (typeof input !== "string") {
			throw new TypeError(`Expected string, got ${typeof input}`);
		}
		return input;
	});
}

function optional(schema) {
	return {
		parse(input) {
			return input === undefined ? undefined : schema.parse(input);
		},
		optional() {
			return this;
		},
		nullable() {
			return nullable(this);
		},
	};
}

function nullable(schema) {
	return {
		parse(input) {
			return input === null ? null : schema.parse(input);
		},
		optional() {
			return optional(this);
		},
		nullable() {
			return this;
		},
	};
}

export { string, optional, nullable };
